import React from 'react';
import styles from './product-listing.module.css';
import Title from '../../title';
import ProductCard from '../../product-card';
import data from './product.json';

const ProductListing: React.FC = () => {
  return (
    <div className={styles.product_listing}>
        <div className='container'>
            <div className={styles.list_container}>
                <Title level="h2" className={styles.title}>Products</Title>
                <Title level="h5" className={styles.subtitle}>Order it for you or for your beloved ones </Title>
                <div className={styles.wrapper_cards}>
                    {data.map(({ id, name, price, img}) => (
                        <div key={id}>
                            <ProductCard

                            imgSrc={img}
                            name={name}
                            price={price}
                            />
                        </div>
                    ))}
                </div>
                <div className={styles.wrapper_cards}>
  {data.map(({ id, name, price, img }) => ( 
    <div key={id}>
      <ProductCard
        imgSrc={img}
        name={name}
        price={price}
      />
    </div>
  ))}
</div>


            </div>
        </div>

    </div>
  )
}

export default ProductListing;
